UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE IFNULL(HOUSE_NUM1, 0) = 0;

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 500 AND 599;

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 900 AND 999;

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE CITY2 IN ('Wiblingwerde', 'Breckerfeld');

SELECT COUNT(*) AS cnt FROM eabl
WHERE ISTABLART_TXT = 'Maschinelle Schätzung - SAP'
  AND substr("Record created on", 1, 4) IN ('2023','2024');

